def assess(record: dict) -> str:
    required = {'window_end', 'watermark', 'event_time', 'case_id', 'allowed_lateness'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    return "PASS" if meets else 'SIDE_OUTPUT_LATE_EVENT'

